+    void pad_line(std::string & line);
+    void scroll_up();
+    void scroll_down();
+    void select();
+    void back();
+    void show_message(std::vector<std::string> message);
+    void show_message(std::string message);
+
+    // Spin Once
+    void spin_once();
+
